const StarRating: React.FC<{ rating: number }> = ({ rating }) => {
  const fullStars = Math.floor(rating);
  const hasHalf = rating - fullStars >= 0.5;
  const emptyStars = 5 - fullStars - (hasHalf ? 1 : 0);

  return (
    <div className="-testi-stars">
      {Array.from({ length: fullStars }, (_, i) => (
        <span key={`full-${i}`} className="-testi-star">
          <FaStar />
        </span>
      ))}
      {hasHalf && (
        <span key="half" className="-testi-star">
          <FaStarHalfAlt />
        </span>
      )}
      {Array.from({ length: emptyStars }, (_, i) => (
        <span key={`empty-${i}`} className="-testi-star">
          <FaRegStar />
        </span>
      ))}
    </div>
  );
};

const TestimonialSection: React.FC = () => {
  const testimonials = staticTestimonials || [];
  const [activeIndex, setActiveIndex] = useState(0);
  const [isAnimating, setIsAnimating] = useState(false);

  useEffect(() => {
    if (testimonials.length === 0) return;
    const interval = setInterval(() => {
      handleNext();
    }, 5000);
    return () => clearInterval(interval);
  }, [activeIndex]);

  const handlePrev = () => {
    if (testimonials.length === 0) return;
    setIsAnimating(true);
    setActiveIndex((prev) => (prev - 1 + testimonials.length) % testimonials.length);
    setTimeout(() => setIsAnimating(false), 500);
  };

  const handleNext = () => {
    if (testimonials.length === 0) return;
    setIsAnimating(true);
    setActiveIndex((prev) => (prev + 1) % testimonials.length);
    setTimeout(() => setIsAnimating(false), 500);
  };

  const handleDotClick = (index: number) => {
    if (index !== activeIndex && testimonials.length > 0) {
      setIsAnimating(true);
      setActiveIndex(index);
      setTimeout(() => setIsAnimating(false), 500);
    }
  };

  if (
    !Array.isArray(testimonials) ||
    testimonials.length === 0 ||
    !testimonials[activeIndex]
  ) {
    return <div className="-testi-testimonial-section">No testimonials available.</div>;
  }

  const currentTestimonial = testimonials[activeIndex];

  return (
    <div className="-testi" id="testimonial">
      <div className="-testi-testimonial-section">
        <header className="-testi-header">
          <h1 className="-testi-section-title-p">Customer Testimonials</h1>
          <p className="-testi-content-p">
            Discover what our clients say about our services and how we've helped them achieve their goals.
          </p>
        </header>

        <div className="-testi-testimonial-container">
          <button className="-testi-nav-button left" onClick={handlePrev}>
            <FaChevronLeft />
          </button>

          <div className={`-testi-testimonial-card ${isAnimating ? '' : '-testi-fade-in'}`}>
            <div className="-testi-quote-icon">
              <FaQuoteLeft />
            </div>

            <p className="-testi-content">{currentTestimonial.content}</p>

            <div className="-testi-user-info">
              <img
                src={currentTestimonial.avatar}
                alt={currentTestimonial.name}
                className="-testi-avatar"
                onError={(e) => {
                  const target = e.target as HTMLImageElement;
                  target.onerror = null;
                  target.src = 'https://via.placeholder.com/70';
                }}
              />
              <div className="-testi-user-details">
                <h4>{currentTestimonial.name}</h4>
                <div className="-testi-role">{currentTestimonial.role}</div>
                <StarRating rating={currentTestimonial.rating} />
              </div>
            </div>
          </div>

          <button className="-testi-nav-button right" onClick={handleNext}>
            <FaChevronRight />
          </button>
        </div>

        <div className="-testi-dots">
          {testimonials.map((_, index) => (
            <span
              key={index}
              className={`-testi-dot ${index === activeIndex ? 'active' : ''}`}
              onClick={() => handleDotClick(index)}
            ></span>
          ))}
        </div>
      </div>
    </div>
  );
};

export default TestimonialSection;
