import React, { useRef, useEffect } from 'react';
import 'aos/dist/aos.css'; // Import AOS styles
import AOS from 'aos';
import './hero.css';
import video from '../../images/herovideo.mp4'
const HeroSection = () => {
  const videoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    // Initialize AOS
    AOS.init({
      duration: 800,
      once: true, // Animations happen only once
    });

    // Set video playback rate
    if (videoRef.current) {
      videoRef.current.playbackRate = 0.7;
    }
  }, []);

  return (
    <section className="hero">
      <div className="video-overlay"></div>
      <video 
        ref={videoRef}
        className="hero-video" 
        autoPlay 
        muted 
        loop 
        playsInline
      >
       <source src={video} type="video/mp4" />
        Your browser does not support the video tag.
      </video>
      
      <div className="hero-content">
        <div className="text-container">
          <div className="heading-group">
            <h1 
              className="main-heading"
              data-aos="fade-up"
            >
            Ideal Floors
            </h1>
            <h1 
              className="highlight-heading"
              data-aos="fade-up"
              data-aos-delay="200"
            >
              TAILORED TO YOU
            </h1>
          </div>
          
          <p 
            className="subheading"
            data-aos="fade-up"
            data-aos-delay="300"
          >
            From custom furniture to built-ins we create stunning woodwork with expert detail.
          </p>
          
          <div 
            className="cta-container"
            data-aos="fade-up"
            data-aos-delay="400"
          >
            <a href="/Contact/contact">
              <button className="cta-button">
                REQUEST YOUR SERVICE
                <svg className="arrow-icon" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
                  <path d="M5 12H19M12 5L19 12L12 19" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
                </svg>
              </button>
            </a>
            
            <div className="reviews-container">
              <div className="reviews-number">520+</div>
              <div className="reviews-text">Five-Star Reviews</div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default HeroSection;